#!/usr/bin/env python3
# -*- coding: utf-8 -*-
"""
Applique automatiquement les modifications "Shift" suivantes a ton projet :
  1. Notification privee automatique de "Shift" au ban / debannissement
     (commande /ban, /unban, bouton "Debannir", et nettoyage des bans
     temporaires expires).
  2. Ban avec une duree en secondes (deja gere par le parseur, ce script
     met juste a jour les textes d'aide/erreur pour le mentionner).
  3. Badges rouges "non lu" (nombre) sur les icones de serveur et sur les
     conversations privees.

UTILISATION :
    Placer ce script A LA RACINE de ton projet (le dossier qui contient "src/"),
    puis lancer :
        python3 apply_shift_updates.py

    Chaque fichier existant modifie est d'abord sauvegarde a cote de lui-meme
    sous la forme "<fichier>.bak.AAAAMMJJ_HHMMSS" (meme convention que les
    fichiers .bak deja presents dans le projet), avant d'etre ecrase.
"""

import base64
import datetime
import os
import sys

# {relative_path: (is_new_file, base64_content)}
FILES = {
    'src/lib/shiftBot.js': (True, """"""),
    'src/components/shift/UnreadBadge.jsx': (True, """"""),
    'src/components/shift/ChatArea.jsx': (False, """"""),
    'src/components/shift/ServerSettingsModal.jsx': (False, """"""),
    'src/components/shift/DMSidebar.jsx': (False, """"""),
    'src/pages/ShiftApp.jsx': (False, """"""),
}

def main():
    root = os.path.abspath(os.path.dirname(__file__))
    src_dir = os.path.join(root, "src")
    if not os.path.isdir(src_dir):
        print('Erreur : aucun dossier "src" ici. Place ce script a la racine')
        print('de ton projet (a cote de "src/", "package.json", etc.) puis relance-le.')
        sys.exit(1)

    ts = datetime.datetime.now().strftime("%Y%m%d_%H%M%S")
    created, updated = [], []

    for rel_path, (is_new, b64_content) in FILES.items():
        target = os.path.join(root, rel_path)
        content = base64.b64decode(b64_content)
        os.makedirs(os.path.dirname(target), exist_ok=True)

        if os.path.exists(target):
            backup = f"{target}.bak.{ts}"
            with open(target, "rb") as f:
                old = f.read()
            with open(backup, "wb") as f:
                f.write(old)
            updated.append(rel_path)
            print(f"  Modifie : {rel_path}  (sauvegarde -> {os.path.basename(backup)})")
        else:
            created.append(rel_path)
            print(f"  Cree    : {rel_path}")

        with open(target, "wb") as f:
            f.write(content)

    print()
    print(f"Termine : {len(created)} fichier(s) cree(s), {len(updated)} fichier(s) modifie(s).")
    print()
    print("IMPORTANT (a verifier cote Supabase) :")
    print("  Les messages automatiques de \"Shift\" sont envoyes avec un faux")
    print("  identifiant utilisateur fixe (voir SHIFT_BOT_ID dans src/lib/shiftBot.js).")
    print("  Si les policies RLS des tables \"messages\" / \"dm_conversations\" exigent")
    print("  que sender_id / les participants correspondent a auth.uid(), il faudra")
    print("  les assouplir pour autoriser explicitement cet identifiant.")

if __name__ == "__main__":
    main()
